function getBasePath() {
const baseTag = document.querySelector('base');
if (baseTag) {
return baseTag.getAttribute('href') || '/';
}
return '/';
}
function buildUrl(path) {
const basePath = getBasePath();
const cleanPath = path.startsWith('/') ? path.substring(1) : path;
const cleanBase = basePath.endsWith('/') ? basePath : basePath + '/';
return cleanBase + cleanPath;
}
function escapeHtml(text) {
if (typeof text !== 'string') return '';
const map = {
'&': '&amp;',
'<': '&lt;',
'>': '&gt;',
'"': '&quot;',
"'": '&#039;'
};
return text.replace(/[&<>"']/g, (m) => map[m]);
}
function normalizeString(str) {
if (typeof str !== 'string') return '';
return str
.toLowerCase()
.normalize('NFD')
.replace(/[\u0300-\u036f]/g, '');
}
function debounce(func, wait = 300) {
let timeout;
return function executedFunction(...args) {
const later = () => {
clearTimeout(timeout);
func(...args);
};
clearTimeout(timeout);
timeout = setTimeout(later, wait);
};
}
function validateObject(obj, requiredProps) {
if (!obj || typeof obj !== 'object') return false;
return requiredProps.every(prop => {
return Object.prototype.hasOwnProperty.call(obj, prop) &&
obj[prop] !== null &&
obj[prop] !== undefined;
});
}
function formatDate(date) {
try {
const d = typeof date === 'string' ? new Date(date) : date;
if (isNaN(d.getTime())) return '';
const day = String(d.getDate()).padStart(2, '0');
const month = String(d.getMonth() + 1).padStart(2, '0');
const year = d.getFullYear();
return `${day}/${month}/${year}`;
} catch (error) {
return '';
}
}
function showToast(message, type = 'info', duration = 3000) {
const colors = {
success: '#10b981',
error: '#ef4444',
warning: '#f59e0b',
info: '#3b82f6'
};
const toast = document.createElement('div');
toast.style.cssText = `
position: fixed;
top: 20px;
right: 20px;
background: ${colors[type] || colors.info};
color: white;
padding: 15px 20px;
border-radius: 8px;
box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
z-index: 10000;
animation: slideInRight 0.3s ease-out;
font-weight: 500;
max-width: 300px;
`;
toast.textContent = message;
const style = document.createElement('style');
style.textContent = `
@keyframes slideInRight {
from {
transform: translateX(400px);
opacity: 0;
}
to {
transform: translateX(0);
opacity: 1;
}
}
@keyframes slideOutRight {
from {
transform: translateX(0);
opacity: 1;
}
to {
transform: translateX(400px);
opacity: 0;
}
}
`;
if (!document.querySelector('style[data-toast-animations]')) {
style.setAttribute('data-toast-animations', 'true');
document.head.appendChild(style);
}
document.body.appendChild(toast);
setTimeout(() => {
toast.style.animation = 'slideOutRight 0.3s ease-out';
setTimeout(() => toast.remove(), 300);
}, duration);
}
function handleError(error, context = 'Operação', showUser = true) {
if (showUser) {
showToast(
`Erro ao executar ${context}. Tente novamente.`,
'error'
);
}
}
const replaceFeatherIcons = debounce(() => {
if (typeof feather !== 'undefined') {
feather.replace();
}
}, 100);
const cache = {
store: new Map(),
get(key) {
const item = this.store.get(key);
if (!item) return null;
const now = Date.now();
const ttl = window.UroConstants?.CACHE?.TTL || 300000;
if (now - item.timestamp > ttl) {
this.store.delete(key);
return null;
}
return item.data;
},
set(key, data) {
this.store.set(key, {
data,
timestamp: Date.now()
});
},
delete(key) {
this.store.delete(key);
},
clear() {
this.store.clear();
},
stats() {
return {
size: this.store.size,
keys: Array.from(this.store.keys())
};
}
};
async function fetchWithCache(url, options = {}, useCache = true) {
if (!url || typeof url !== 'string') {
throw new Error('URL inválida fornecida ao fetchWithCache');
}
const cacheKey = `fetch_${url}`;
if (useCache) {
const cached = cache.get(cacheKey);
if (cached) {
return cached;
}
}
try {
const response = await fetch(url, options);
if (!response.ok) {
throw new Error(`HTTP error! status: ${response.status}`);
}
let data = await response.json();
        // Auto-unwrap formato Decap CMS: {items: [...]} → [...]
        if (data && !Array.isArray(data) && Array.isArray(data.items)) {
            data = data.items;
        }
if (useCache) {
cache.set(cacheKey, data);
}
return data;
} catch (error) {
throw error;
}
}
function showLoading(element) {
if (!element || !(element instanceof HTMLElement)) {
return;
}
element.classList.add('loading');
}
function hideLoading(element) {
if (!element || !(element instanceof HTMLElement)) {
return;
}
element.classList.remove('loading');
}
window.UroUtils = {
getBasePath,
buildUrl,
escapeHtml,
normalizeString,
debounce,
validateObject,
formatDate,
showToast,
handleError,
replaceFeatherIcons,
cache,
fetchWithCache,
showLoading,
hideLoading
};